    // Convert string parameters to character vectors to handle non-ASCII characters
    let str1_chars: Vec<char> = str1.chars().collect();
    let str2_chars: Vec<char> = str2.chars().collect();

    // Get and store length of these strings
    let str1_len = str1_chars.len();
    let str2_len = str2_chars.len();

    // Base cases
    if str1_len == 0 {
        return Ok(str2_len as i32);
    } else if str2_len == 0 {
        return Ok(str1_len as i32);
    } else if equal(&str1_chars, &str2_chars)? {
        return Ok(0);
    }

    // Create a map to track character positions
    let mut da = HashMap::<char, i32>::new();
    for i in 0..str1_len {
        da.insert(str1_chars[i], 0);
    }
    for j in 0..str2_len {
        da.insert(str2_chars[j], 0);
    }

    // 2D Array for distance matrix: matrix[0..str1.len()+2][0..str2.len()+2]
    let mut matrix = vec![vec![0; str2_len + 2]; str1_len + 2];

    // Maximum possible distance
    let max_dist = (str1_len + str2_len) as i32;

    // Initialize matrix
    matrix[0][0] = max_dist;
    for i in 0..=str1_len {
        matrix[i + 1][0] = max_dist;
        matrix[i + 1][1] = i as i32;
    }
    for j in 0..=str2_len {
        matrix[0][j + 1] = max_dist;
        matrix[1][j + 1] = j as i32;
    }

    // Process edit distance
    for i in 1..=str1_len {
        let mut db = 0;
        for j in 1..=str2_len {
            // Get last position of current character in str2
            let i1 = *da.get(&str2_chars[j - 1]).unwrap_or(&0);
            let j1 = db;
            let cost = if str1_chars[i - 1] == str2_chars[j - 1] { 0 } else { 1 };

            if cost == 0 {
                db = j as i32;
            }

            matrix[i + 1][j + 1] = min(
                min(
                    matrix[i + 1][j] + 1,    // Addition
                    matrix[i][j + 1] + 1     // Deletion
                ),
                min(
                    matrix[i][j] + cost,     // Substitution
                    matrix[i1 as usize + 1][j1 as usize + 1] + (i as i32 - i1 - 1) + 1 + (j as i32 - j1 - 1)  // Transposition
                )
            );
        }

        // Update position of current character
        da.insert(str1_chars[i - 1], i as i32);
    }

