		{"multi_emoji/same", args{"🙂😄🙂😄", "🙂😄🙂😄"}, 0, false},
		{"multi_emoji/diff", args{"🙂😄🙂😄", "😄🙂😄🙂"}, 4, false},
		{"mixed/same", args{"a🙂b😄", "a🙂b😄"}, 0, false},
		{"mixed/diff", args{"a🙂b😄", "a😄b🙂"}, 2, false},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := HammingDistance(tt.args.str1, tt.args.str2)
			if (err != nil) != tt.wantErr {
				t.Errorf("HammingDistanceEquivalence() error = %v, wantErr %v", err, tt.wantErr)
				return
			}
			if err == nil && got != tt.want {
				t.Errorf("HammingDistanceEquivalence() = %v, want %v", got, tt.want)
			}
		})
	}
}

