pub fn lcs_edit_distance(str1: &str, str2: &str) -> Result<i32> {
    if str1.is_empty() {
        return Ok(str2.len() as i32);
    } else if str2.is_empty() {
        return Ok(str1.len() as i32);
    } else if str1 == str2 {
        return Ok(0);
    }
    let lcs_len = lcs(str1, str2)?;
    // Convert strings to char vectors to count characters, not bytes
    let str1_chars = str1.chars().count() as i32;
    let str2_chars = str2.chars().count() as i32;
    let edit_distance = (str1_chars - lcs_len) + (str2_chars - lcs_len);
    Ok(edit_distance)
}

