		name string
		args args
		want map[string]int
	}{
		{"empty string", args{"", 5}, map[string]int{}},
		{"zero k", args{"hello", 0}, map[string]int{}},
		{"basic ascii", args{"hello", 2}, map[string]int{"he": 1, "el": 1, "ll": 1, "lo": 1}},
		{"repeated chars", args{"aaaa", 2}, map[string]int{"aa": 3}},
		{"unicode characters", args{"こんにちは", 2}, map[string]int{"こん": 1, "んに": 1, "にち": 1, "ちは": 1}},
		{"emojis", args{"🙂😄🙂", 2}, map[string]int{"🙂😄": 1, "😄🙂": 1}},
		{"mixed unicode", args{"hello世界", 2}, map[string]int{"he": 1, "el": 1, "ll": 1, "lo": 1, "o世": 1, "世界": 1}},
		{"k equal to string length", args{"hello", 5}, map[string]int{"hello": 1}},
		{"k larger than string length", args{"hi", 5}, map[string]int{}},
		{"whitespace", args{"a b c", 2}, map[string]int{"a ": 1, " b": 1, "b ": 1, " c": 1}},
		{"special chars", args{"!@#$%", 2}, map[string]int{"!@": 1, "@#": 1, "#$": 1, "$%": 1}},
	}

