pub(crate) fn matching_index(
    str1: &str,
    str2: &str,
    distance: usize,
) -> Result<f32, anyhow::Error> {
    let chars1: Vec<char> = str1.chars().collect();
    let chars2: Vec<char> = str2.chars().collect();

    // Handle edge cases similar to Go implementation
    if chars1.is_empty() && chars2.is_empty() {
        return Ok(0.0);
    }

    // Find the longer string and use it for calculation
    let longer_len = chars1.len().max(chars2.len());

    // To match Go implementation, we always use (longer_len - distance) / longer_len
    // We need to ensure the result is not negative
    let result = if distance >= longer_len {
        0.0
    } else {
        ((longer_len - distance) as f32) / (longer_len as f32)
    };

    Ok(result)
}

